    //    Preserve old compound format so existing documents are still found by key.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // 3. HasIndex now throws for Cosmos entities — removed.
    //    Manage indexing via the Cosmos container's indexing policy instead.
}

